import json
import logging
import re
import boto3
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

ALLOWED_TOPIC_ARNS = None

NOTIFICATION_TYPES = {
    'alert': {
        'subject_prefix': '[ALERT]',
        'default_subject': 'System Alert',
    },
    'info': {
        'subject_prefix': '[INFO]',
        'default_subject': 'Information Notice',
    },
    'warning': {
        'subject_prefix': '[WARNING]',
        'default_subject': 'Warning Notice',
    },
    'critical': {
        'subject_prefix': '[CRITICAL]',
        'default_subject': 'Critical Alert',
    },
    'transactional': {
        'subject_prefix': '[TRANSACTION]',
        'default_subject': 'Transaction Notification',
    },
}

ALLOWED_ACCOUNT_ID = None
ALLOWED_REGION = None


def _get_allowed_topic_arns():
    """
    Retrieve allowed topic ARNs from environment or configuration.
    In production, these should come from environment variables or AWS Systems Manager Parameter Store.
    """
    import os
    global ALLOWED_TOPIC_ARNS, ALLOWED_ACCOUNT_ID, ALLOWED_REGION

    if ALLOWED_TOPIC_ARNS is None:
        allowed_arns_str = os.environ.get('ALLOWED_TOPIC_ARNS', '')
        if allowed_arns_str:
            ALLOWED_TOPIC_ARNS = [arn.strip() for arn in allowed_arns_str.split(',') if arn.strip()]
        else:
            ALLOWED_TOPIC_ARNS = []

    if ALLOWED_ACCOUNT_ID is None:
        ALLOWED_ACCOUNT_ID = os.environ.get('ALLOWED_ACCOUNT_ID', '')

    if ALLOWED_REGION is None:
        ALLOWED_REGION = os.environ.get('ALLOWED_REGION', os.environ.get('AWS_REGION', ''))

    return ALLOWED_TOPIC_ARNS, ALLOWED_ACCOUNT_ID, ALLOWED_REGION


def validate_topic_arn(topic_arn):
    """
    Validate that the topic ARN is well-formed and belongs to the allowed set.
    Prevents open subscription / publishing to arbitrary topics.
    """
    if not topic_arn or not isinstance(topic_arn, str):
        raise ValueError("Topic ARN must be a non-empty string.")

    arn_pattern = re.compile(
        r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$'
    )
    if not arn_pattern.match(topic_arn):
        raise ValueError(f"Invalid SNS topic ARN format: {topic_arn}")

    allowed_arns, allowed_account_id, allowed_region = _get_allowed_topic_arns()

    arn_parts = topic_arn.split(':')
    arn_region = arn_parts[3]
    arn_account_id = arn_parts[4]

    if allowed_account_id and arn_account_id != allowed_account_id:
        raise ValueError(
            f"Topic ARN account '{arn_account_id}' is not in the allowed account."
        )

    if allowed_region and arn_region != allowed_region:
        raise ValueError(
            f"Topic ARN region '{arn_region}' is not in the allowed region."
        )

    if allowed_arns and topic_arn not in allowed_arns:
        raise ValueError(
            f"Topic ARN '{topic_arn}' is not in the allowed topics list."
        )

    return True


def sanitize_message(message):
    """Sanitize message content to prevent injection attacks."""
    if not message or not isinstance(message, str):
        raise ValueError("Message must be a non-empty string.")

    if len(message) > 256 * 1024:
        raise ValueError("Message exceeds maximum allowed size of 256KB.")

    return message.strip()


def sanitize_subject(subject):
    """Sanitize subject line."""
    if not subject or not isinstance(subject, str):
        return None

    subject = subject.strip()
    subject = re.sub(r'[^\x20-\x7E]', '', subject)

    if len(subject) > 99:
        subject = subject[:99]

    return subject if subject else None


def build_message_attributes(notification_type, custom_attributes=None):
    """Build SNS message attributes for filtering and metadata."""
    attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type,
        },
    }

    if custom_attributes and isinstance(custom_attributes, dict):
        for key, value in custom_attributes.items():
            safe_key = re.sub(r'[^a-zA-Z0-9_.-]', '', str(key))
            if safe_key and isinstance(value, str) and len(value) <= 256:
                attributes[safe_key] = {
                    'DataType': 'String',
                    'StringValue': value,
                }

    return attributes


def publish_standard_message(topic_arn, message, subject, notification_type, message_attributes):
    """Publish a standard (non-structured) message to SNS."""
    publish_params = {
        'TopicArn': topic_arn,
        'Message': message,
        'MessageAttributes': message_attributes,
    }

    if subject:
        publish_params['Subject'] = subject

    response = sns_client.publish(**publish_params)
    return response


def publish_structured_message(topic_arn, message_body, subject, notification_type, message_attributes):
    """
    Publish a structured message with per-protocol payloads.
    Allows different message formats for email, SMS, HTTP, Lambda, etc.
    """
    if isinstance(message_body, dict):
        structured_message = {}

        structured_message['default'] = message_body.get(
            'default', json.dumps(message_body, default=str)
        )

        if 'email' in message_body:
            structured_message['email'] = message_body['email']

        if 'sms' in message_body:
            sms_msg = message_body['sms']
            if len(sms_msg) > 140:
                sms_msg = sms_msg[:137] + '...'
            structured_message['sms'] = sms_msg

        if 'lambda' in message_body:
            lambda_payload = message_body['lambda']
            if isinstance(lambda_payload, dict):
                structured_message['lambda'] = json.dumps(lambda_payload, default=str)
            else:
                structured_message['lambda'] = str(lambda_payload)

        if 'http' in message_body or 'https' in message_body:
            http_payload = message_body.get('https', message_body.get('http'))
            if isinstance(http_payload, dict):
                structured_message['http'] = json.dumps(http_payload, default=str)
                structured_message['https'] = json.dumps(http_payload, default=str)
            else:
                structured_message['http'] = str(http_payload)
                structured_message['https'] = str(http_payload)

        message_json = json.dumps(structured_message, default=str)
    else:
        message_json = json.dumps({
            'default': str(message_body),
        })

    publish_params = {
        'TopicArn': topic_arn,
        'Message': message_json,
        'MessageStructure': 'json',
        'MessageAttributes': message_attributes,
    }

    if subject:
        publish_params['Subject'] = subject

    response = sns_client.publish(**publish_params)
    return response


def lambda_handler(event, context):
    """
    AWS Lambda handler for publishing messages to SNS topics.

    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "message": "Your message content" or { "default": "...", "email": "...", "sms": "..." },
        "subject": "Optional subject line",
        "notification_type": "alert|info|warning|critical|transactional",
        "structured": false,
        "message_attributes": {
            "custom_key": "custom_value"
        }
    }

    Or batch mode:
    {
        "batch": true,
        "messages": [
            {
                "topic_arn": "...",
                "message": "...",
                "notification_type": "alert"
            },
            ...
        ]
    }
    """
    logger.info("Event notification system invoked.")

    try:
        is_batch = event.get('batch', False)

        if is_batch:
            return _handle_batch(event)
        else:
            return _handle_single(event)

    except ValueError as ve:
        logger.error(f"Validation error: {ve}")
        return {
            'statusCode': 400,
            'body': json.dumps({
                'error': 'Validation Error',
                'message': str(ve),
            }),
        }
    except ClientError as ce:
        error_code = ce.response['Error']['Code']
        error_message = ce.response['Error']['Message']
        logger.error(f"AWS ClientError: {error_code} - {error_message}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'AWS Service Error',
                'code': error_code,
                'message': error_message,
            }),
        }
    except Exception as e:
        logger.error(f"Unexpected error: {e}", exc_info=True)
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': 'Internal Error',
                'message': 'An unexpected error occurred while publishing the notification.',
            }),
        }


def _handle_single(event):
    """Handle a single message publish request."""
    topic_arn = event.get('topic_arn')
    message = event.get('message')
    subject = event.get('subject')
    notification_type = event.get('notification_type', 'info')
    is_structured = event.get('structured', False)
    custom_attributes = event.get('message_attributes', {})

    if notification_type not in NOTIFICATION_TYPES:
        raise ValueError(
            f"Invalid notification_type '{notification_type}'. "
            f"Must be one of: {', '.join(NOTIFICATION_TYPES.keys())}"
        )

    validate_topic_arn(topic_arn)

    type_config = NOTIFICATION_TYPES[notification_type]

    if not subject:
        subject = type_config['default_subject']

    subject = f"{type_config['subject_prefix']} {subject}"
    subject = sanitize_subject(subject)

    message_attributes = build_message_attributes(notification_type, custom_attributes)

    if is_structured and isinstance(message, dict):
        if isinstance(message.get('default'), str):
            message['default'] = sanitize_message(message['default'])
        response = publish_structured_message(
            topic_arn, message, subject, notification_type, message_attributes
        )
    else:
        if isinstance(message, dict):
            message = json.dumps(message, default=str)
        message = sanitize_message(message)
        response = publish_standard_message(
            topic_arn, message, subject, notification_type, message_attributes
        )

    message_id = response.get('MessageId')
    logger.info(
        f"Successfully published {notification_type} notification. "
        f"MessageId: {message_id}, TopicArn: {topic_arn}"
    )

    return {
        'statusCode': 200,
        'body': json.dumps({
            'message': 'Notification published successfully.',
            'message_id': message_id,
            'notification_type': notification_type,
            'topic_arn': topic_arn,
        }),
    }


def _handle_batch(event):
    """Handle batch message publish requests."""
    messages = event.get('messages', [])

    if not messages or not isinstance(messages, list):
        raise ValueError("Batch mode requires a non-empty 'messages' list.")

    if len(messages) > 100:
        raise ValueError("Batch size cannot exceed 100 messages.")

    results = []
    errors = []

    for idx, msg_event in enumerate(messages):
        try:
            result = _handle_single(msg_event)
            result_body = json.loads(result['body'])
            results.append({
                'index': idx,
                'status': 'success',
                'message_id': result_body.get('message_id'),
            })
        except (ValueError, ClientError) as e:
            logger.error(f"Error publishing batch message at index {idx}: {e}")
            errors.append({
                'index': idx,
                'status': 'error',
                'error': str(e),
            })

    total = len(messages)
    success_count = len(results)
    error_count = len(errors)

    logger.info(
        f"Batch publish complete: {success_count}/{total} succeeded, "
        f"{error_count}/{total} failed."
    )

    status_code = 200 if error_count == 0 else (207 if success_count > 0 else 500)

    return {
        'statusCode': status_code,
        'body': json.dumps({
            'message': 'Batch publish complete.',
            'total': total,
            'successful': success_count,
            'failed': error_count,
            'results': results,
            'errors': errors,
        }),
    }